import{_ as a,c as e,o,a1 as r}from"./chunks/framework.DILC4Csi.js";const b=JSON.parse('{"title":"Интеграция с Bear: автоматическое сохранение планов | Plannotator","description":"Изучите настройку интеграции Plannotator с Bear. Автоматическое сохранение одобренных планов через x-callback-url, интеллектуальная генерация тегов, накопление знаний и архивирование планов.","frontmatter":{"title":"Интеграция с Bear: автоматическое сохранение планов | Plannotator","sidebarTitle":"Автосохранение в Bear","subtitle":"Интеграция с Bear: автоматическое сохранение одобренных планов | Plannotator","description":"Изучите настройку интеграции Plannotator с Bear. Автоматическое сохранение одобренных планов через x-callback-url, интеллектуальная генерация тегов, накопление знаний и архивирование планов.","tags":["Интеграция","Bear","Приложение для заметок","Накопление знаний"],"prerequisite":["installation-claude-code","platforms-plan-review-basics"],"order":3},"headers":[],"relativePath":"ru/backnotprop/plannotator/advanced/bear-integration/index.md","filePath":"ru/backnotprop/plannotator/advanced/bear-integration/index.md"}'),l={name:"ru/backnotprop/plannotator/advanced/bear-integration/index.md"};function i(n,t,d,s,c,p){return o(),e("div",null,[...t[0]||(t[0]=[r(`<h1 id="интеграция-с-bear-автоматическое-сохранение-одобренных-планов" tabindex="-1">Интеграция с Bear: автоматическое сохранение одобренных планов <a class="header-anchor" href="#интеграция-с-bear-автоматическое-сохранение-одобренных-планов" aria-label="Permalink to &quot;Интеграция с Bear: автоматическое сохранение одобренных планов&quot;">​</a></h1><h2 id="чему-вы-научитесь" tabindex="-1">Чему вы научитесь <a class="header-anchor" href="#чему-вы-научитесь" aria-label="Permalink to &quot;Чему вы научитесь&quot;">​</a></h2><p>После включения интеграции с Bear каждый раз при одобрении плана Plannotator автоматически сохраняет его в ваши заметки Bear, включая:</p><ul><li>Автоматически сгенерированный заголовок (извлечённый из плана)</li><li>Интеллектуальные теги (название проекта, ключевые слова, язык программирования)</li><li>Полное содержимое плана</li></ul><p>Таким образом вы сможете управлять всеми одобренными планами в одном месте для удобного последующего просмотра и накопления знаний.</p><h2 id="текущие-трудности" tabindex="-1">Текущие трудности <a class="header-anchor" href="#текущие-трудности" aria-label="Permalink to &quot;Текущие трудности&quot;">​</a></h2><p>Возможно, вы сталкивались с такими ситуациями:</p><ul><li>ИИ сгенерировал отличный план, но хочется сохранить его для будущего использования</li><li>Ручное копирование планов в Bear слишком утомительно</li><li>Планы разных проектов смешиваются без системы тегов</li></ul><p>С интеграцией Bear все эти проблемы решаются автоматически.</p><h2 id="когда-использовать-этот-подход" tabindex="-1">Когда использовать этот подход <a class="header-anchor" href="#когда-использовать-этот-подход" aria-label="Permalink to &quot;Когда использовать этот подход&quot;">​</a></h2><ul><li>Вы используете Bear как основное приложение для заметок</li><li>Нужно архивировать одобренные планы для базы знаний</li><li>Хотите быстро находить исторические планы по тегам</li></ul><div class="info custom-block"><p class="custom-block-title">О Bear</p><p>Bear — это приложение для Markdown-заметок на macOS с поддержкой тегов, шифрования, синхронизации и других функций. Если вы ещё не установили его, посетите <a href="https://bear.app/" target="_blank" rel="noreferrer">bear.app</a> для получения информации.</p></div><h2 id="🎒-подготовка" tabindex="-1">🎒 Подготовка <a class="header-anchor" href="#🎒-подготовка" aria-label="Permalink to &quot;🎒 Подготовка&quot;">​</a></h2><ul><li>Установлен Plannotator (см. <a href="./../../start/installation-claude-code/">руководство по установке</a>)</li><li>Установлен Bear и работает корректно</li><li>Знакомы с базовым процессом рецензирования планов (см. <a href="./../../platforms/plan-review-basics/">Основы рецензирования планов</a>)</li></ul><h2 id="основная-идея" tabindex="-1">Основная идея <a class="header-anchor" href="#основная-идея" aria-label="Permalink to &quot;Основная идея&quot;">​</a></h2><p>Ядро интеграции с Bear — протокол <strong>x-callback-url</strong>:</p><ol><li>Включите интеграцию с Bear в UI Plannotator (сохраняется в localStorage браузера)</li><li>При одобрении плана Plannotator отправляет URL <code>bear://x-callback-url/create</code></li><li>Система использует команду <code>open</code> для автоматического открытия Bear и создания заметки</li><li>Содержимое плана, заголовок и теги заполняются автоматически</li></ol><p><strong>Ключевые особенности</strong>:</p><ul><li>Не требуется настройка пути к vault (в отличие от Obsidian)</li><li>Интеллектуальная генерация тегов (максимум 7)</li><li>Автоматическое сохранение при одобрении плана</li></ul><div class="tip custom-block"><p class="custom-block-title">Отличие от Obsidian</p><p>Интеграция с Bear проще — не нужно настраивать путь к vault, достаточно одного переключателя. Но Obsidian позволяет указать папку для сохранения и предлагает больше возможностей настройки.</p></div><h2 id="пошаговое-руководство" tabindex="-1">Пошаговое руководство <a class="header-anchor" href="#пошаговое-руководство" aria-label="Permalink to &quot;Пошаговое руководство&quot;">​</a></h2><h3 id="шаг-1-откроите-настроики-plannotator" tabindex="-1">Шаг 1: Откройте настройки Plannotator <a class="header-anchor" href="#шаг-1-откроите-настроики-plannotator" aria-label="Permalink to &quot;Шаг 1: Откройте настройки Plannotator&quot;">​</a></h3><p>Когда AI Agent сгенерирует план и откроет UI Plannotator, нажмите кнопку ⚙️ <strong>Settings</strong> в правом верхнем углу.</p><p><strong>Ожидаемый результат</strong>: Откроется панель настроек с несколькими параметрами конфигурации</p><h3 id="шаг-2-включите-интеграцию-с-bear" tabindex="-1">Шаг 2: Включите интеграцию с Bear <a class="header-anchor" href="#шаг-2-включите-интеграцию-с-bear" aria-label="Permalink to &quot;Шаг 2: Включите интеграцию с Bear&quot;">​</a></h3><p>В панели настроек найдите раздел <strong>Bear Notes</strong> и нажмите переключатель.</p><p><strong>Почему</strong> Переключатель изменится с серого (отключено) на синий (включено), и настройка сохранится в localStorage браузера.</p><p><strong>Ожидаемый результат</strong>:</p><ul><li>Переключатель Bear Notes станет синим</li><li>Описание: &quot;Auto-save approved plans to Bear&quot;</li></ul><h3 id="шаг-3-одобрите-план" tabindex="-1">Шаг 3: Одобрите план <a class="header-anchor" href="#шаг-3-одобрите-план" aria-label="Permalink to &quot;Шаг 3: Одобрите план&quot;">​</a></h3><p>После завершения рецензирования плана нажмите кнопку <strong>Approve</strong> внизу.</p><p><strong>Почему</strong> Plannotator прочитает настройки Bear, и если интеграция включена, одновременно с одобрением вызовет x-callback-url Bear.</p><p><strong>Ожидаемый результат</strong>:</p><ul><li>Bear автоматически откроется</li><li>Появится окно новой заметки</li><li>Заголовок и содержимое уже заполнены</li><li>Теги автоматически сгенерированы (начинаются с <code>#</code>)</li></ul><h3 id="шаг-4-проверьте-сохраненную-заметку" tabindex="-1">Шаг 4: Проверьте сохранённую заметку <a class="header-anchor" href="#шаг-4-проверьте-сохраненную-заметку" aria-label="Permalink to &quot;Шаг 4: Проверьте сохранённую заметку&quot;">​</a></h3><p>В Bear проверьте новую заметку:</p><ul><li>Правильный ли заголовок (из H1 плана)</li><li>Полное ли содержимое (весь текст плана)</li><li>Корректны ли теги (название проекта, ключевые слова, язык программирования)</li></ul><p><strong>Ожидаемый результат</strong>: Структура заметки примерно такая:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## User Authentication</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[Полное содержимое плана...]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">#plannotator #myproject #authentication #typescript #api</span></span></code></pre></div><h2 id="контрольныи-список-✅" tabindex="-1">Контрольный список ✅ <a class="header-anchor" href="#контрольныи-список-✅" aria-label="Permalink to &quot;Контрольный список ✅&quot;">​</a></h2><ul><li>[ ] Переключатель Bear Notes в Settings включён</li><li>[ ] После одобрения плана Bear открывается автоматически</li><li>[ ] Заголовок заметки соответствует H1 плана</li><li>[ ] Заметка содержит полное содержимое плана</li><li>[ ] Теги включают <code>#plannotator</code> и название проекта</li></ul><h2 id="типичные-проблемы" tabindex="-1">Типичные проблемы <a class="header-anchor" href="#типичные-проблемы" aria-label="Permalink to &quot;Типичные проблемы&quot;">​</a></h2><h3 id="bear-не-открывается-автоматически" tabindex="-1">Bear не открывается автоматически <a class="header-anchor" href="#bear-не-открывается-автоматически" aria-label="Permalink to &quot;Bear не открывается автоматически&quot;">​</a></h3><p><strong>Причина</strong>: Команда <code>open</code> не выполнилась, возможно:</p><ul><li>Bear не установлен или не загружен из App Store</li><li>URL-схема Bear перехвачена другим приложением</li></ul><p><strong>Решение</strong>:</p><ol><li>Убедитесь, что Bear установлен корректно</li><li>Проверьте вручную в терминале: <code>open &quot;bear://x-callback-url/create?title=test&quot;</code></li></ol><h3 id="теги-не-соответствуют-ожиданиям" tabindex="-1">Теги не соответствуют ожиданиям <a class="header-anchor" href="#теги-не-соответствуют-ожиданиям" aria-label="Permalink to &quot;Теги не соответствуют ожиданиям&quot;">​</a></h3><p><strong>Причина</strong>: Теги генерируются автоматически по следующим правилам:</p><ul><li>Обязательный: <code>#plannotator</code></li><li>Обязательный: название проекта (из имени git-репозитория или директории)</li><li>Опционально: до 3 ключевых слов из заголовка H1 (исключая стоп-слова)</li><li>Опционально: теги языков программирования из блоков кода (исключая json/yaml/markdown)</li><li>Максимум 7 тегов</li></ul><p><strong>Решение</strong>:</p><ul><li>Если теги не подходят, отредактируйте их вручную в Bear</li><li>Если название проекта неверное, проверьте конфигурацию git-репозитория или имя директории</li></ul><h3 id="план-одобрен-но-не-сохранен" tabindex="-1">План одобрен, но не сохранён <a class="header-anchor" href="#план-одобрен-но-не-сохранен" aria-label="Permalink to &quot;План одобрен, но не сохранён&quot;">​</a></h3><p><strong>Причина</strong>:</p><ul><li>Переключатель Bear не включён (проверьте Settings)</li><li>Сетевая ошибка или таймаут Bear</li><li>Содержимое плана пустое</li></ul><p><strong>Решение</strong>:</p><ol><li>Убедитесь, что переключатель в Settings синий (включён)</li><li>Проверьте терминал на наличие ошибок (<code>[Bear] Save failed:</code>)</li><li>Повторно одобрите план</li></ol><h2 id="подробности-механизма-генерации-тегов" tabindex="-1">Подробности механизма генерации тегов <a class="header-anchor" href="#подробности-механизма-генерации-тегов" aria-label="Permalink to &quot;Подробности механизма генерации тегов&quot;">​</a></h2><p>Plannotator интеллектуально генерирует теги для быстрого поиска планов в Bear. Правила генерации:</p><table tabindex="0"><thead><tr><th>Источник тега</th><th>Пример</th><th>Приоритет</th></tr></thead><tbody><tr><td>Фиксированный тег</td><td><code>#plannotator</code></td><td>Обязательный</td></tr><tr><td>Название проекта</td><td><code>#myproject</code>, <code>#plannotator</code></td><td>Обязательный</td></tr><tr><td>Ключевые слова H1</td><td><code>#authentication</code>, <code>#api</code></td><td>Опционально (макс. 3)</td></tr><tr><td>Язык программирования</td><td><code>#typescript</code>, <code>#python</code></td><td>Опционально</td></tr></tbody></table><p><strong>Список стоп-слов</strong> (не становятся тегами):</p><ul><li><code>the</code>, <code>and</code>, <code>for</code>, <code>with</code>, <code>this</code>, <code>that</code>, <code>from</code>, <code>into</code></li><li><code>plan</code>, <code>implementation</code>, <code>overview</code>, <code>phase</code>, <code>step</code>, <code>steps</code></li></ul><p><strong>Исключённые языки программирования</strong> (не становятся тегами):</p><ul><li><code>json</code>, <code>yaml</code>, <code>yml</code>, <code>text</code>, <code>txt</code>, <code>markdown</code>, <code>md</code></li></ul><details class="details custom-block"><summary>Пример: процесс генерации тегов</summary><p>Допустим, заголовок плана &quot;Implementation Plan: User Authentication System in TypeScript&quot;, блоки кода содержат Python и JSON:</p><ol><li><strong>Фиксированный тег</strong>: <code>#plannotator</code></li><li><strong>Название проекта</strong>: <code>#myproject</code> (предположим, имя git-репозитория)</li><li><strong>Ключевые слова H1</strong>: <ul><li><code>implementation</code> → исключено (стоп-слово)</li><li><code>plan</code> → исключено (стоп-слово)</li><li><code>user</code> → сохранено → <code>#user</code></li><li><code>authentication</code> → сохранено → <code>#authentication</code></li><li><code>system</code> → сохранено → <code>#system</code></li><li><code>typescript</code> → сохранено → <code>#typescript</code></li></ul></li><li><strong>Языки программирования</strong>: <ul><li><code>python</code> → сохранено → <code>#python</code></li><li><code>json</code> → исключено (в списке исключений)</li></ul></li></ol><p>Итоговые теги: <code>#plannotator #myproject #user #authentication #system #typescript #python</code> (7 — достигнут лимит)</p></details><h2 id="сравнение-с-интеграциеи-obsidian" tabindex="-1">Сравнение с интеграцией Obsidian <a class="header-anchor" href="#сравнение-с-интеграциеи-obsidian" aria-label="Permalink to &quot;Сравнение с интеграцией Obsidian&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Характеристика</th><th>Интеграция Bear</th><th>Интеграция Obsidian</th></tr></thead><tbody><tr><td>Сложность настройки</td><td>Простая (только переключатель)</td><td>Средняя (нужно выбрать vault и папку)</td></tr><tr><td>Хранение</td><td>Внутри приложения Bear</td><td>По указанному пути vault</td></tr><tr><td>Имя файла</td><td>Управляется Bear автоматически</td><td><code>Title - Mon D, YYYY H-MMam.md</code></td></tr><tr><td>Frontmatter</td><td>Нет (Bear не поддерживает)</td><td>Есть (created, source, tags)</td></tr><tr><td>Кроссплатформенность</td><td>Только macOS</td><td>macOS/Windows/Linux</td></tr><tr><td>x-callback-url</td><td>✅ Используется</td><td>❌ Прямая запись файла</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Как выбрать</p><ul><li>Если вы используете только macOS и предпочитаете Bear: интеграция с Bear проще</li><li>Если нужна кроссплатформенность или настраиваемый путь хранения: интеграция с Obsidian гибче</li><li>Если хотите использовать оба: можно включить обе интеграции (при одобрении план сохранится в оба места)</li></ul></div><h2 id="итоги-урока" tabindex="-1">Итоги урока <a class="header-anchor" href="#итоги-урока" aria-label="Permalink to &quot;Итоги урока&quot;">​</a></h2><ul><li>Интеграция с Bear работает через протокол x-callback-url, настройка проста</li><li>Достаточно включить переключатель в Settings, указывать путь не нужно</li><li>При одобрении плана он автоматически сохраняется в Bear</li><li>Теги генерируются интеллектуально: название проекта, ключевые слова, язык программирования (максимум 7)</li><li>По сравнению с Obsidian, Bear проще, но менее функционален</li></ul><h2 id="анонс-следующего-урока" tabindex="-1">Анонс следующего урока <a class="header-anchor" href="#анонс-следующего-урока" aria-label="Permalink to &quot;Анонс следующего урока&quot;">​</a></h2><blockquote><p>В следующем уроке мы изучим <strong><a href="./../remote-mode/">Удалённый режим / Devcontainer</a></strong>.</p><p>Вы узнаете:</p><ul><li>Как использовать Plannotator в удалённых средах (SSH, devcontainer, WSL)</li><li>Настройка фиксированного порта и проброса портов</li><li>Открытие страницы рецензирования в браузере из удалённой среды</li></ul></blockquote><hr><h2 id="приложение-справочник-по-исходному-коду" tabindex="-1">Приложение: справочник по исходному коду <a class="header-anchor" href="#приложение-справочник-по-исходному-коду" aria-label="Permalink to &quot;Приложение: справочник по исходному коду&quot;">​</a></h2><details><summary><strong>Нажмите, чтобы развернуть расположение исходного кода</strong></summary><blockquote><p>Дата обновления: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Функция</th><th>Путь к файлу</th><th>Строки</th></tr></thead><tbody><tr><td>Интерфейс конфигурации Bear</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L18-L20" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>18-20</td></tr><tr><td>Сохранение в Bear</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L234-L257" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>234-257</td></tr><tr><td>Извлечение тегов</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L34-L74" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>34-74</td></tr><tr><td>Извлечение заголовка</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L94-L105" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>94-105</td></tr><tr><td>Интерфейс настроек Bear</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/bear.ts#L15-L17" target="_blank" rel="noreferrer"><code>packages/ui/utils/bear.ts</code></a></td><td>15-17</td></tr><tr><td>Чтение настроек Bear</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/bear.ts#L22-L26" target="_blank" rel="noreferrer"><code>packages/ui/utils/bear.ts</code></a></td><td>22-26</td></tr><tr><td>Сохранение настроек Bear</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/bear.ts#L31-L33" target="_blank" rel="noreferrer"><code>packages/ui/utils/bear.ts</code></a></td><td>31-33</td></tr><tr><td>UI-компонент настроек</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/Settings.tsx#L496-L518" target="_blank" rel="noreferrer"><code>packages/ui/components/Settings.tsx</code></a></td><td>496-518</td></tr><tr><td>Вызов Bear при одобрении</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/editor/App.tsx#L512-L514" target="_blank" rel="noreferrer"><code>packages/editor/App.tsx</code></a></td><td>512-514</td></tr><tr><td>Обработка Bear на сервере</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L250-L257" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>250-257</td></tr></tbody></table><p><strong>Ключевые функции</strong>:</p><ul><li><code>saveToBear(config: BearConfig)</code>: сохраняет план в Bear через x-callback-url</li><li><code>extractTags(markdown: string)</code>: интеллектуально извлекает теги из содержимого плана (максимум 7)</li><li><code>extractTitle(markdown: string)</code>: извлекает заголовок заметки из H1 плана</li><li><code>getBearSettings()</code>: читает настройки интеграции Bear из localStorage</li><li><code>saveBearSettings(settings)</code>: сохраняет настройки интеграции Bear в localStorage</li></ul><p><strong>Ключевые константы</strong>:</p><ul><li><code>STORAGE_KEY_ENABLED = &#39;plannotator-bear-enabled&#39;</code>: ключ настроек Bear в localStorage</li></ul><p><strong>Формат URL Bear</strong>:</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bear</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//x-callback-url/create?title={title}&amp;text={content}&amp;open_note=no</span></span></code></pre></div></details>`,75)])])}const u=a(l,[["render",i]]);export{b as __pageData,u as default};
